                type="checkbox"
                checked={!l.hidden}
                disabled={pending === l.id}
                data-testid={`vv-links-visible-${l.id}`}
                onChange={() => void toggle(l)}
              />
            </td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}

